def run_length_encode(s):
    if not s:
        return []
    result = []
    current_char = s[0]
    count = 1
    for char in s[1:]:
        if char == current_char:
            count += 1
        else:
            result.append((current_char, count))
            current_char = char
            count = 1
    result.append((current_char, count))
    return result

def interval_intersection(intervals1, intervals2):
    if not intervals1 or not intervals2:
        return []

    result = []
    i, j = 0, 0

    while i < len(intervals1) and j < len(intervals2):
        start1, end1 = intervals1[i]
        start2, end2 = intervals2[j]

        if start1 <= end2 and start2 <= end1:
            # Overlapping or touching intervals
            new_end = min(end1, end2)
            result.append([start1, new_end])
            i += 1
            j += 1
        elif start1 < start2:
            i += 1
        else:
            j += 1

    return result

