def lis_length(nums):
    if not nums:
        return 0
    tails = []
    for num in nums:
        if not tails or num > tails[-1]:
            tails.append(num)
        else:
            idx = bisect.bisect_left(tails, num)
            if idx < len(tails):
                tails[idx] = num
    return len(tails)
